#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag? -res : res ;
}
const int N=2e5+10,M=4e5+10;
struct Graph
{
	int head[N],des[M],nxt[M],idx[M],val[M],drc[N],cnt;
	inline void ins(int x,int y,int z,int d){nxt[++cnt]=head[x];drc[cnt]=d;idx[cnt]=z;des[cnt]=y;head[x]=cnt;}
}a,b;
int dfn[N],low[N],dcc[N],dep,stk[N],top,cnt,s[N],ans[N];bool vis[N];
void tarjan(int u,int fa=0)
{
//	printf("%d %d\n",u,fa);
	dfn[u]=low[u]=++dep;stk[++top]=u;grep(a,u,i)if(i^fa)
	{
		int v=a.des[i];if(!dfn[v])
		{
			tarjan(v,i^1);low[u]=min(low[u],low[v]);
			if(low[v]>dfn[u]){++cnt;int z;do{dcc[z=stk[top--]]=cnt;}while(z!=v);}
		}
		else low[u]=min(low[u],dfn[v]);
	}
}
void dfs(int u,int idx=0,int drc=0)
{
//	printf("%d %d %d\n",u,idx,drc);
	vis[u]=1;grep(b,u,i){int v=b.des[i];if(!vis[v])dfs(v,b.idx[i],b.drc[i]),s[u]+=s[v];}
	if(s[u])ans[idx]=(s[u]*drc<0?1:2);
}
int main()
{
	a.cnt=1;int n=read(),m=read();rep(1,m,i){int x=read(),y=read();a.ins(x,y,i,1);a.ins(y,x,i,-1);}
	rep(1,n,i)if(!dfn[i])dep=0,tarjan(i,0);++cnt;while(top)dcc[stk[top--]]=cnt;//rep(1,n,i)printf("%d ",dcc[i]);puts("");
	rep(1,n,i)grep(a,i,j)if(dcc[i]^dcc[a.des[j]])b.ins(dcc[i],dcc[a.des[j]],a.idx[j],a.drc[j]);
//	puts("start");rep(1,cnt,i)grep(b,i,j)printf("%d %d %d %d\n",i,b.des[j],b.idx[j],b.drc[j]);puts("completed");
	int Q=read();rep(1,Q,i)s[dcc[read()]]++,s[dcc[read()]]--;rep(1,cnt,i)if(!vis[i])dfs(i);
	rep(1,m,i)putchar(!ans[i]?'B':(ans[i]!=1?'L':'R'));return 0;
}
